#include <iostream>
#include <unordered_map>
#include <chrono>
#include <memory>

class Session {
public:
    std::string userId;
    int sessionId;
    std::chrono::system_clock::time_point expiryTime;

    Session(int sessionId, const std::string& userId, int durationMinutes)
        : sessionId(sessionId), userId(userId) {
        expiryTime = std::chrono::system_clock::now() + std::chrono::minutes(durationMinutes);
    }

    bool isExpired() const {
        return std::chrono::system_clock::now() > expiryTime;
    }
};

class SessionCache {
private:
    std::unordered_map<int, std::shared_ptr<Session>> cache;

public:
    void createSession(int sessionId, const std::string& userId, int durationMinutes) {
        if (cache.find(sessionId) != cache.end()) {
            std::cout << "Session already exists. Invalidating and recreating." << std::endl;
            invalidateSession(sessionId);
        }
        auto session = std::make_shared<Session>(sessionId, userId, durationMinutes);
        cache[sessionId] = session;
    }

    bool accessSession(int sessionId) {
        auto it = cache.find(sessionId);
        if (it != cache.end()) {
            if (!it->second->isExpired()) {
                return true;
            } else {
                invalidateSession(sessionId);
            }
        }
        return false;
    }

    void invalidateSession(int sessionId) {
        auto it = cache.find(sessionId);
        if (it != cache.end()) {
            std::cout << "Invalidating session: " << sessionId << std::endl;
            cache.erase(it);
        }
    }
};

